package main

import (
    "errors"
    "fmt"
)

// ---- Custom error type ----
type GameError struct {
    Code    int
    Message string
}

func (e GameError) Error() string {
    return fmt.Sprintf("[%d] %s", e.Code, e.Message)
}

// ---- Error constants ----
var ErrPlayerNotFound = errors.New("player not found")
var ErrInvalidInput = errors.New("invalid input")
var ErrNotEnoughGold = errors.New("not enough gold")

// ---- Functions that return errors ----
func findPlayer(name string) (string, error) {
    if name == "" {
        return "", ErrInvalidInput
    }
    if name == "Hero" {
        return "Found player: Hero", nil
    }
    return "", ErrPlayerNotFound
}

func purchaseItem(gold int, cost int) (int, error) {
    if gold < cost {
        return gold, ErrNotEnoughGold
    }
    return gold - cost, nil
}

func divide(a, b float64) (float64, error) {
    if b == 0 {
        return 0, errors.New("division by zero")
    }
    return a / b, nil
}

func main() {
    // ---- Error handling ----
    fmt.Println("=== Basic Error Handling ===")

    result, err := findPlayer("Hero")
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println(result)
    }

    // ---- Error not found ----
    result, err = findPlayer("Gandalf")
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println(result)
    }

    // ---- Custom error ----
    fmt.Println("\n=== Custom Error ===")
    gold, err := purchaseItem(50, 100)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Remaining gold:", gold)
    }

    // ---- Error wrapping ----
    fmt.Println("\n=== Error Wrapping ===")
    err = fmt.Errorf("operation failed: %w", ErrPlayerNotFound)
    fmt.Println(err)

    // ---- Check error type ----
    if errors.Is(err, ErrPlayerNotFound) {
        fmt.Println("It's a player not found error")
    }

    // ---- Division with error ----
    result2, err := divide(10, 0)
    if err != nil {
        fmt.Println("Division error:", err)
    } else {
        fmt.Println("Result:", result2)
    }

    // ---- Multiple error handling ----
    fmt.Println("\n=== Multiple Errors ===")
    errs := []error{
        ErrPlayerNotFound,
        ErrInvalidInput,
        ErrNotEnoughGold,
    }

    for _, e := range errs {
        fmt.Println("Error:", e)
    }
}

