package main

import (
    "errors"
    "fmt"
)

func validateAge(age int) error {
    if age < 0 {
        return errors.New("age cannot be negative")
    }
    if age > 150 {
        return errors.New("age must be under 150")
    }
    return nil
}

func main() {
    err := validateAge(-5)
    if err != nil {
        fmt.Println("Error:", err)
    }

    err = validateAge(200)
    if err != nil {
        fmt.Println("Error:", err)
    }

    err = validateAge(25)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Valid age")
    }
}
